from collections import defaultdict

def bws_scores(tasks: list[dict]) -> dict:
    """
    Compute BWS scores from annotation tasks.
    Each task: {items: [str, ...], best: str, worst: str}
    """
    best_count  = defaultdict(int)
    worst_count = defaultdict(int)
    appear      = defaultdict(int)
    for task in tasks:
        for item in task['items']:
            appear[item] += 1
        best_count[task['best']]   += 1
        worst_count[task['worst']] += 1
    return {
        item: (best_count[item] - worst_count[item]) / appear[item]
        for item in appear
    }

tasks = [
    {'items': ['A', 'B', 'C'], 'best': 'A', 'worst': 'C'},
    {'items': ['A', 'B', 'D'], 'best': 'B', 'worst': 'A'},
    {'items': ['B', 'C', 'D'], 'best': 'B', 'worst': 'C'},
    {'items': ['A', 'C', 'D'], 'best': 'D', 'worst': 'C'},
]
print(bws_scores(tasks))
# {'A': 0.0, 'B': 0.67, 'C': -1.0, 'D': 0.33}
